const currentItem = $input.all()[0].json;
const pageId = String(currentItem.id);
const props = currentItem.properties;

const jobTitle = props['Job Title']?.title?.[0]?.plain_text || 'Not provided';
const company = props['Company']?.rich_text?.[0]?.plain_text || 'Not provided';
const location = props['Location']?.rich_text?.[0]?.plain_text || 'Not provided';
const jobDesc = (props['Job Description']?.rich_text?.[0]?.plain_text || 'Not provided').slice(0, 1200);
const aiScore = props['AI Score']?.number || 0;
const verdict = props['AI Verdict']?.select?.name || 'Good Fit';

const resume = `CANDIDATE: Nibras Hassan V M | CCNA Certified | Dubai, UAE

CURRENT ROLE: IT Admin Intern, AVANI Ibn Battuta Dubai (Sep 2025 - Present)
- Provided L1 IT and network support, resolving LAN/Wi-Fi connectivity, access, and hardware issues
- Supported enterprise Wi-Fi infrastructure (Aruba Wi-Fi Controller, Airangel HSIA), monitoring access points and resolving connectivity incidents
- Administered Active Directory, managing user accounts, group policies, and access permissions
- Assisted in network documentation, asset tracking, and incident records for audit readiness
- Performed backup operations and basic server health checks to ensure system availability
- Supported Microsoft 365 user provisioning, mailbox access, and basic troubleshooting

PREVIOUS: System Admin, Axtella Properties, Bahrain (Aug 2024 - Jul 2025)
- Installing, configuring, and upgrading hardware and software
- Troubleshooting and maintaining CCTV, wired and wireless connections ensuring reliable connectivity
- Managing inventory of hardware and software assets

PREVIOUS: Network Support Engineer, Golden Telecom, Riyadh, Saudi Arabia (May 2023 - Jun 2024)
- Configured and optimized routers and switches, reducing latency
- Worked with NOC teams to troubleshoot issues ensuring SLA compliance
- Adhered to standardized escalation processes, improving incident resolution time
- Conducted hands-on training on router security and best practices

EDUCATION: B.Tech Electrical and Electronics Engineering, PRIST University (2022)

CERTIFICATIONS: CCNA (Cisco ID: CSCO14897563, valid till Apr 2028), Wireshark (Udemy), Active Directory Administrator (Server Academy)

SKILLS:
- Networking: TCP/IP, OSI, VLANs, NAT, DHCP, DNS, STP, QoS
- Routing: Static and Dynamic Routing, IPv6, subnetting (VLSM/CIDR)
- Tools: Wireshark, Cisco Packet Tracer, PuTTY, Microsoft 365, Active Directory, Aruba Wi-Fi Controller
- Languages: English, Hindi, Arabic, Malayalam
- Emirates ID valid, based in Dubai`;

const result = {
  pageId: pageId,
  tailored_resume: 'Not generated yet'
};

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': 'YOUR_ANTHROPIC_API_KEY',
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 800,
      system: 'You are an expert resume writer specializing in IT and networking roles in the UAE market. You tailor resumes to specific job descriptions. Be concise, ATS-friendly, and use strong action verbs. Never fabricate experience — only reframe what exists.',
      messages: [{
        role: 'user',
        content: 'Tailor this candidate resume for the job below. Return ONLY the tailored content in this exact format with no extra commentary:\n\nSUMMARY: [2-sentence tailored professional summary]\n\nKEY SKILLS: [comma-separated list of 8-10 skills matching this job]\n\nTAILORED BULLETS:\n- [rewritten bullet 1 most relevant to this job]\n- [rewritten bullet 2]\n- [rewritten bullet 3]\n- [rewritten bullet 4]\n- [rewritten bullet 5]\n\nGAP NOTE: [one sentence on any gap between candidate and job requirements]\n\n---JOB---\nTitle: ' + jobTitle + '\nCompany: ' + company + '\nLocation: ' + location + '\nDescription: ' + jobDesc + '\n\n---CANDIDATE RESUME---\n' + resume
      }]
    },
    json: true
  });

  const raw = String(response && response.content && response.content[0] ? response.content[0].text : 'Error getting response');
  result.tailored_resume = raw;

} catch (e) {
  result.tailored_resume = 'Error: ' + String(e && e.message ? e.message : e).slice(0, 200);
}

return [{ json: result }];
